class Solution {
    public boolean canChange(String start, String target) {
        int n = start.length();
        int lCount = 0, rCount = 0;
        for (int i = 0; i < n; i++) {
            if (start.charAt(i) == 'L' && target.charAt(i) == '_') lCount++;
            if (start.charAt(i) == 'R' && target.charAt(i) == '_') rCount--;
            if (start.charAt(i) == '_' && target.charAt(i) == 'L') lCount--;
            if (start.charAt(i) == '_' && target.charAt(i) == 'R') rCount++;
        }
        return lCount == 0 && rCount == 0;
    }
}
